  "questionProse": [
    "`<menu>` 元素在 HTML 中用于什么？"
  ],
  "hintsProse": [],
  "explanationProse": [
    "[`<menu>`](https://developer.mozilla.org/en-US/docs/Web/HTML/Element/menu) 元素表示命令或交互控件的列表。\n\n    如果你的列表是导航链接，请使用 `<nav>` 配合 `<ul>`。对于类似工具栏的控件或命令列表，请使用 `<menu>`。"
  ]
}
